        /// <summary>
        /// 전체 항목 썸네일을 2줄 가로 배치로 생성/갱신
        /// </summary>
        private void RefreshPhotoList()
        {
            panelPhotoScroll.SuspendLayout();
            panelPhotoScroll.Controls.Clear();

            int count = Math.Min(_items.Count, 15);  // 최대 15개 표시
            int cols = (count + 1) / 2;  // 2줄이므로 한 줄에 cols개
            int panelW = panelPhotoScroll.ClientSize.Width;
            int panelH = panelPhotoScroll.ClientSize.Height;

            int gap = 3;
            int itemW = (panelW - gap * (cols + 1)) / cols;
            if (itemW < 60) itemW = 60;
            int lblH = 13;
            int rowH = (panelH - gap) / 2;  // 2줄 균등 분배
            int thumbH = rowH - lblH - gap;

            for (int i = 0; i < count; i++)
            {
                int col = i % cols;
                int row = i / cols;
                int px = gap + col * (itemW + gap);
                int py = row * rowH;

                // 항목 번호 + 이름 라벨
                var lbl = new Label();
                lbl.Text = $"{i + 1}. {_items[i][0]}";
                lbl.Location = new Point(px, py);
                lbl.Size = new Size(itemW, lblH);
                lbl.Font = new Font("맑은 고딕", 6.5F);
                lbl.ForeColor = Color.FromArgb(180, 180, 180);
                lbl.Tag = i;
                lbl.Cursor = Cursors.Hand;
                lbl.Click += PhotoThumb_Click;
                panelPhotoScroll.Controls.Add(lbl);

                // 썸네일 PictureBox
                var pb = new PictureBox();
                pb.Location = new Point(px, py + lblH);
                pb.Size = new Size(itemW, thumbH);
                pb.SizeMode = PictureBoxSizeMode.Zoom;
                pb.BorderStyle = BorderStyle.FixedSingle;
                pb.BackColor = Color.FromArgb(35, 35, 35);
                pb.Tag = i;
                pb.Cursor = Cursors.Hand;
                pb.Click += PhotoThumb_Click;
                LoadPhotoInto(pb, i);
                panelPhotoScroll.Controls.Add(pb);
            }

            panelPhotoScroll.ResumeLayout();

            if (count > 0)
                SelectPhotoThumb(0);
        }

        /// <summary>
        /// 지정 인덱스의 사진을 PictureBox에 로드
        /// </summary>
        private void LoadPhotoInto(PictureBox pb, int itemIndex)
        {
            string prefix = (itemIndex + 1).ToString("D2");
            string[] exts = { ".jpg", ".jpeg", ".png", ".bmp", ".gif" };
            foreach (var ext in exts)
            {
                string path = Path.Combine(_photoPath, prefix + ext);
                if (File.Exists(path))
                {
                    try
                    {
                        using (var fs = new FileStream(path, FileMode.Open, FileAccess.Read))
                        {
                            pb.Image?.Dispose();
                            pb.Image = Image.FromStream(fs);
                        }
                        return;
                    }
                    catch { }
                }
            }
            pb.Image?.Dispose();
            pb.Image = null;
        }

        /// <summary>
        /// 썸네일 클릭 → 해당 항목 선택
        /// </summary>
        private void PhotoThumb_Click(object sender, EventArgs e)
        {
            int idx = -1;
            if (sender is Control ctrl && ctrl.Tag is int tagIdx)
                idx = tagIdx;
            if (idx < 0 || idx >= dgv.Rows.Count) return;

            SelectPhotoThumb(idx);

            // 그리드에서 해당 행 선택
            dgv.ClearSelection();
            dgv.Rows[idx].Selected = true;
            dgv.CurrentCell = dgv.Rows[idx].Cells["colItem"];
        }

        /// <summary>
        /// 선택된 썸네일 하이라이트 (테두리 색상 변경)
        /// </summary>
        private void SelectPhotoThumb(int index)
        {
            _selectedPhotoIndex = index;
            lblPhotoTitle.Text = index >= 0 && index < _items.Count
                ? $"{index + 1}. {_items[index][0]}"
                : "참조 사진";

            foreach (Control c in panelPhotoScroll.Controls)
            {
                if (c is PictureBox pb && pb.Tag is int pbIdx)
                {
                    pb.BackColor = (pbIdx == index)
                        ? Color.FromArgb(0, 90, 158)  // 선택 - 파란색
                        : Color.FromArgb(35, 35, 35);  // 미선택
                }
            }

            // 2줄 배치에서는 스크롤 불필요
        }

        /// <summary>
        /// 파일 다이알로그로 참조사진 선택/설정
        /// </summary>
        private void BtnSetPhoto_Click(object sender, EventArgs e)
        {
            int rowIdx = _selectedPhotoIndex;
            if (rowIdx < 0)
            {
                if (dgv.CurrentRow != null)
                    rowIdx = dgv.CurrentRow.Index;
            }
            if (rowIdx < 0 || rowIdx >= _items.Count)
            {
                MessageBox.Show("사진을 설정할 항목을 먼저 선택하세요.", "알림",
                    MessageBoxButtons.OK, MessageBoxIcon.Information);
                return;
            }

            string prefix = (rowIdx + 1).ToString("D2");

            using (var ofd = new OpenFileDialog())
            {
                ofd.Filter = "이미지 파일|*.jpg;*.jpeg;*.png;*.bmp;*.gif|모든 파일|*.*";
                ofd.Title = $"항목 {rowIdx + 1} ({_items[rowIdx][0]}) 참조 사진 선택";

                if (ofd.ShowDialog() != DialogResult.OK) return;

                try
                {
                    if (!Directory.Exists(_photoPath))
                        Directory.CreateDirectory(_photoPath);

                    // 기존 사진 삭제
                    string[] exts = { ".jpg", ".jpeg", ".png", ".bmp", ".gif" };
                    foreach (var ext in exts)
                    {
                        string oldPath = Path.Combine(_photoPath, prefix + ext);
                        if (File.Exists(oldPath))
                            File.Delete(oldPath);
                    }

                    // 새 사진 복사
                    string newExt = Path.GetExtension(ofd.FileName).ToLower();
                    string destPath = Path.Combine(_photoPath, prefix + newExt);
                    File.Copy(ofd.FileName, destPath, true);

                    // 해당 썸네일만 갱신
                    foreach (Control c in panelPhotoScroll.Controls)
                    {
                        if (c is PictureBox pb && pb.Tag is int pbIdx && pbIdx == rowIdx)
                        {
                            LoadPhotoInto(pb, rowIdx);
                            break;
                        }
                    }

                    Logger.Log($"[일상점검] 항목 {rowIdx + 1} 사진 설정 완료");
                }
                catch (Exception ex)
                {
                    MessageBox.Show($"사진 설정 실패: {ex.Message}", "오류",
                        MessageBoxButtons.OK, MessageBoxIcon.Error);
                }
            }
        }

