        #region 셀 클릭 → O/X 토글 + 로그

        private void Dgv_CellClick(object sender, DataGridViewCellEventArgs e)
        {
            if (_loading || e.RowIndex < 0 || e.ColumnIndex < FIXED_COL_COUNT) return;

            string colName = dgv.Columns[e.ColumnIndex].Name;
            if (!colName.StartsWith("colDay")) return;

            // colDay{d}_{M|A|E} 파싱
            string suffix = colName.Substring(6); // "d_M" or "dd_M"
            string[] parts = suffix.Split('_');
            if (parts.Length != 2) return;

            int day;
            if (!int.TryParse(parts[0], out day)) return;
            string shiftKey = parts[1];

            int daysInMonth = DateTime.DaysInMonth(_currentMonth.Year, _currentMonth.Month);
            if (day > daysInMonth) return;

            var cell = dgv.Rows[e.RowIndex].Cells[e.ColumnIndex];
            string current = cell.Value?.ToString()?.Trim() ?? "";

            // 순환: "" → O → X → ""
            string next;
            if (current == "") next = "O";
            else if (current == "O") next = "X";
            else next = "";

            cell.Value = next;
            ApplyCellColor(cell, next, colName);

            // 교대 이름 변환
            int shiftIdx = Array.IndexOf(SHIFT_KEYS, shiftKey);
            string shiftName = shiftIdx >= 0 ? SHIFT_FULL[shiftIdx] : shiftKey;

            string itemName = dgv.Rows[e.RowIndex].Cells["colItem"].Value?.ToString() ?? "";
            LogCheckAction(e.RowIndex + 1, itemName, day, shiftName, current, next);

            SaveData();
        }

        private void ApplyCellColor(DataGridViewCell cell, string value, string colName = "")
        {
            if (value == "O")
            {
                cell.Style.ForeColor = Color.LimeGreen;
                cell.Style.BackColor = Color.FromArgb(30, 60, 30);
            }
            else if (value == "X")
            {
                cell.Style.ForeColor = Color.Red;
                cell.Style.BackColor = Color.FromArgb(70, 25, 25);
            }
            else
            {
                cell.Style.ForeColor = ThemeManager.DarkTheme.TextPrimary;
                // 교대별 기본 배경색 복원
                if (colName.EndsWith("_M"))
                    cell.Style.BackColor = Color.FromArgb(38, 38, 48);
                else if (colName.EndsWith("_A"))
                    cell.Style.BackColor = Color.FromArgb(38, 44, 38);
                else if (colName.EndsWith("_E"))
                    cell.Style.BackColor = Color.FromArgb(44, 38, 38);
                else
                    cell.Style.BackColor = ThemeManager.DarkTheme.BackgroundMedium;
            }
        }

