        /// <summary>
        /// 체크 데이터 저장 (다른 범위 데이터 보존)
        /// </summary>
        private void SaveData()
        {
            if (_loading) return;

            try
            {
                // 기존 데이터 로드 (다른 범위 데이터 유지)
                var existingData = LoadExistingData();

                // 현재 그리드 데이터를 기존 데이터에 병합
                GetRangeStartEnd(out int startDay, out int endDay);

                for (int i = 0; i < dgv.Rows.Count; i++)
                {
                    string itemKey = $"Item{i + 1}";
                    if (!existingData.ContainsKey(itemKey))
                        existingData[itemKey] = new Dictionary<string, string>();

                    for (int d = startDay; d <= endDay; d++)
                    {
                        for (int s = 0; s < 3; s++)
                        {
                            string colName = $"colDay{d}_{SHIFT_KEYS[s]}";
                            string dataKey = $"Day{d}_{SHIFT_KEYS[s]}";

                            if (dgv.Columns.Contains(colName))
                            {
                                string val = dgv.Rows[i].Cells[colName].Value?.ToString()?.Trim() ?? "";
                                if (!string.IsNullOrEmpty(val))
                                    existingData[itemKey][dataKey] = val;
                                else
                                    existingData[itemKey].Remove(dataKey);
                            }
                        }
                    }
                }

                // 파일 저장
                string filePath = GetDataFilePath();
                using (var sw = new StreamWriter(filePath, false, System.Text.Encoding.UTF8))
                {
                    sw.WriteLine("[Header]");
                    sw.WriteLine($"Dept={txtDept.Text}");
                    sw.WriteLine($"Supervisor={txtSupervisor.Text}");
                    sw.WriteLine($"EquipName={txtEquipName.Text}");
                    sw.WriteLine($"Quality={txtQuality.Text}");
                    sw.WriteLine($"EquipNo={txtEquipNo.Text}");
                    sw.WriteLine($"Writer={txtWriter.Text}");
                    sw.WriteLine($"Reviewer={txtReviewer.Text}");
                    sw.WriteLine($"Approver={txtApprover.Text}");
                    sw.WriteLine($"ProdSign={txtProdSign.Text}");
                    sw.WriteLine($"QualSign={txtQualSign.Text}");
                    sw.WriteLine();

                    // 항목 데이터를 Item 번호 순으로 저장
                    var sortedKeys = existingData.Keys
                        .OrderBy(k =>
                        {
                            int num;
                            return int.TryParse(k.Replace("Item", ""), out num) ? num : 999;
                        })
                        .ToList();

                    foreach (var key in sortedKeys)
                    {
                        sw.WriteLine($"[{key}]");
                        foreach (var data in existingData[key].OrderBy(k => k.Key))
                            sw.WriteLine($"{data.Key}={data.Value}");
                        sw.WriteLine();
                    }
                }
            }
            catch (Exception ex)
            {
                Logger.Error($"[일상점검] 저장 실패: {ex.Message}");
            }
        }

        /// <summary>
        /// 파일에서 기존 데이터 로드 (다른 범위 데이터 보존용)
        /// </summary>
        private Dictionary<string, Dictionary<string, string>> LoadExistingData()
        {
            var result = new Dictionary<string, Dictionary<string, string>>();
            string filePath = GetDataFilePath();
            if (!File.Exists(filePath)) return result;

            try
            {
                string currentSection = "";
                foreach (var line in File.ReadAllLines(filePath, System.Text.Encoding.UTF8))
                {
                    string trimmed = line.Trim();
                    if (string.IsNullOrEmpty(trimmed)) continue;

                    if (trimmed.StartsWith("[") && trimmed.EndsWith("]"))
                    {
                        currentSection = trimmed.Substring(1, trimmed.Length - 2);
                        continue;
                    }

                    int eqIdx = trimmed.IndexOf('=');
                    if (eqIdx < 0) continue;
                    string key = trimmed.Substring(0, eqIdx);
                    string val = trimmed.Substring(eqIdx + 1);

                    if (currentSection == "Header") continue;

                    if (currentSection.StartsWith("Item"))
                    {
                        if (!result.ContainsKey(currentSection))
                            result[currentSection] = new Dictionary<string, string>();
                        result[currentSection][key] = val;
                    }
                }
            }
            catch { }
            return result;
        }

        /// <summary>
        /// 체크 데이터 로드
        /// </summary>
        private void LoadData()
        {
            _loading = true;
            string filePath = GetDataFilePath();

            if (!File.Exists(filePath))
            {
                txtDept.Text = "생기/공무팀";
                txtSupervisor.Text = "설비관리담당자";
                txtEquipName.Text = "";
                txtQuality.Text = "19기";
                txtEquipNo.Text = "IM-000-RW-01-32";
                _loading = false;
                return;
            }

            try
            {
                string currentSection = "";
                foreach (var line in File.ReadAllLines(filePath, System.Text.Encoding.UTF8))
                {
                    string trimmed = line.Trim();
                    if (string.IsNullOrEmpty(trimmed)) continue;

                    if (trimmed.StartsWith("[") && trimmed.EndsWith("]"))
                    {
                        currentSection = trimmed.Substring(1, trimmed.Length - 2);
                        continue;
                    }

                    int eqIdx = trimmed.IndexOf('=');
                    if (eqIdx < 0) continue;
                    string key = trimmed.Substring(0, eqIdx);
                    string val = trimmed.Substring(eqIdx + 1);

                    if (currentSection == "Header")
                    {
                        switch (key)
                        {
                            case "Dept": txtDept.Text = val; break;
                            case "Supervisor": txtSupervisor.Text = val; break;
                            case "EquipName": txtEquipName.Text = val; break;
                            case "Quality": txtQuality.Text = val; break;
                            case "EquipNo": txtEquipNo.Text = val; break;
                            case "Writer": txtWriter.Text = val; break;
                            case "Reviewer": txtReviewer.Text = val; break;
                            case "Approver": txtApprover.Text = val; break;
                            case "ProdSign": txtProdSign.Text = val; break;
                            case "QualSign": txtQualSign.Text = val; break;
                        }
                    }
                    else if (currentSection.StartsWith("Item"))
                    {
                        int itemNo;
                        if (!int.TryParse(currentSection.Substring(4), out itemNo)) continue;
                        if (itemNo < 1 || itemNo > dgv.Rows.Count) continue;

                        // 새 형식: Day{d}_{M|A|E}
                        if (key.Contains("_"))
                        {
                            string colName = $"col{key}";
                            if (dgv.Columns.Contains(colName))
                            {
                                var cell = dgv.Rows[itemNo - 1].Cells[colName];
                                cell.Value = val;
                                ApplyCellColor(cell, val, colName);
                            }
                        }
                        // 하위 호환: 기존 Day{d} 형식 → 아침(M)으로 매핑
                        else if (key.StartsWith("Day"))
                        {
                            int dayNo;
                            if (!int.TryParse(key.Substring(3), out dayNo)) continue;
                            string colName = $"colDay{dayNo}_M";
                            if (dgv.Columns.Contains(colName))
                            {
                                var cell = dgv.Rows[itemNo - 1].Cells[colName];
                                cell.Value = val;
                                ApplyCellColor(cell, val, colName);
                            }
                        }
                    }
                }
            }
            catch (Exception ex)
            {
                Logger.Error($"[일상점검] 로드 실패: {ex.Message}");
            }

            _loading = false;
        }

        #endregion

        #region 체크 로그 기록

        private void LogCheckAction(int itemNo, string itemName, int day, string shift, string oldVal, string newVal)
        {
            try
            {
                string logPath = GetLogFilePath();
                string timestamp = DateTime.Now.ToString("yyyy-MM-dd HH:mm:ss");
                string oldDisplay = string.IsNullOrEmpty(oldVal) ? "-" : oldVal;
                string newDisplay = string.IsNullOrEmpty(newVal) ? "-" : newVal;

                string logLine;
                if (day == 0)
                    logLine = $"[{timestamp}] 항목 {itemNo} ({itemName}) | {newDisplay}";
                else
                    logLine = $"[{timestamp}] 항목 {itemNo} ({itemName}) | {day}일 {shift} | {oldDisplay} → {newDisplay}";

                File.AppendAllText(logPath, logLine + Environment.NewLine, System.Text.Encoding.UTF8);
            }
            catch { }
        }

        #endregion

        #region PDF 출력 (3페이지: 범위별)

        private void BtnPdf_Click(object sender, EventArgs e)
        {
            using (var sfd = new SaveFileDialog())
            {
                sfd.Filter = "PDF 파일|*.pdf";
                sfd.FileName = $"점검체크시트_{_currentMonth:yyyy_MM}.pdf";

                if (sfd.ShowDialog() != DialogResult.OK) return;

                try
                {
                    _printRange = 0;  // 첫 페이지부터

                    using (var pd = new PrintDocument())
                    {
                        pd.PrintPage += PrintCheckSheet;
                        pd.DefaultPageSettings.Landscape = true;
                        pd.DefaultPageSettings.Margins = new Margins(30, 30, 30, 30);

                        bool pdfPrinterFound = false;
                        foreach (string printer in PrinterSettings.InstalledPrinters)
                        {
                            if (printer.Contains("Microsoft Print to PDF"))
                            {
                                pd.PrinterSettings.PrinterName = printer;
                                pdfPrinterFound = true;
                                break;
                            }
                        }

                        if (!pdfPrinterFound)
                        {
                            MessageBox.Show("'Microsoft Print to PDF' 프린터를 찾을 수 없습니다.\n인쇄 대화상자에서 PDF 프린터를 선택해주세요.",
                                "알림", MessageBoxButtons.OK, MessageBoxIcon.Warning);

                            using (var printDlg = new PrintDialog())
                            {
                                printDlg.Document = pd;
                                if (printDlg.ShowDialog() != DialogResult.OK) return;
                            }
                            pd.Print();
                        }
                        else
                        {
                            pd.PrinterSettings.PrintToFile = true;
                            pd.PrinterSettings.PrintFileName = sfd.FileName;
                            pd.Print();
                        }
                    }

                    if (File.Exists(sfd.FileName))
                    {
                        System.Diagnostics.Process.Start(sfd.FileName);
                        LogCheckAction(0, "PDF 출력", 0, "", "", sfd.FileName);
                    }
                }
                catch (Exception ex)
                {
                    MessageBox.Show($"PDF 생성 실패: {ex.Message}", "오류",
                        MessageBoxButtons.OK, MessageBoxIcon.Error);
                }
            }
        }

        /// <summary>
        /// 체크시트 인쇄 렌더링 (범위별 페이지)
        /// </summary>
        private void PrintCheckSheet(object sender, PrintPageEventArgs e)
        {
            Graphics g = e.Graphics;
            var area = e.MarginBounds;
            float x = area.Left;
            float y = area.Top;
            float pageW = area.Width;

            // 현재 인쇄 범위
            GetRangeStartEnd(_printRange, out int startDay, out int endDay);
            int daysInMonth = DateTime.DaysInMonth(_currentMonth.Year, _currentMonth.Month);
            if (endDay > daysInMonth) endDay = daysInMonth;
            int dayCount = endDay - startDay + 1;
            int shiftColCount = dayCount * 3;

            // 전체 데이터 로드 (그리드에 없는 범위 포함)
            var allData = LoadExistingData();

            int rowCount = _items.Count;

            // 폰트
            var fontTitle = new Font("맑은 고딕", 12, FontStyle.Bold);
            var fontHeader = new Font("맑은 고딕", 7);
            var fontHeaderBold = new Font("맑은 고딕", 7, FontStyle.Bold);
            var fontCell = new Font("맑은 고딕", 6.5f);
            var fontCellBold = new Font("맑은 고딕", 7, FontStyle.Bold);
            var fontShift = new Font("맑은 고딕", 5.5f);

            var penBlack = new Pen(Color.Black, 0.5f);
            var penBold = new Pen(Color.Black, 1.2f);
            var brushBlack = Brushes.Black;
            var brushGreen = new SolidBrush(Color.FromArgb(0, 128, 0));
            var brushRed = new SolidBrush(Color.FromArgb(200, 0, 0));
            var sfCenter = new StringFormat { Alignment = StringAlignment.Center, LineAlignment = StringAlignment.Center };
            var sfLeft = new StringFormat { Alignment = StringAlignment.Near, LineAlignment = StringAlignment.Center };

            // === 제목 ===
            string rangeText = $"({startDay}~{endDay}일)";
            g.DrawString($"(설비/용접조건) 점검 체크시트 {rangeText}", fontTitle, brushBlack, x + pageW / 2, y, sfCenter);
            y += 24;

            // === 헤더 정보 ===
            string headerLine1 = $"관리부서: {txtDept.Text}    관리감독: {txtSupervisor.Text}    설비명칭: {txtEquipName.Text}";
            string headerLine2 = $"품질: {txtQuality.Text}    설비번호: {txtEquipNo.Text}    " +
                                 $"작성: {txtWriter.Text}    검토: {txtReviewer.Text}    승인: {txtApprover.Text}    " +
                                 $"{_currentMonth:yyyy년 MM월}";
            g.DrawString(headerLine1, fontHeader, brushBlack, x, y);
            y += 13;
            g.DrawString(headerLine2, fontHeader, brushBlack, x, y);
            y += 16;

            // === 테이블 ===
            // 고정 컬럼 폭
            float colNo = 20;
            float colItem = 120;
            float colStd = 100;
            float colMethod = 40;
            float colType = 40;
            float fixedW = colNo + colItem + colStd + colMethod + colType;

            // 교대 컬럼 폭
            float shiftColW = (pageW - fixedW) / shiftColCount;

            // 행 높이
            float availableH = area.Bottom - y - 25;
            float dayHeaderH = 14;
            float shiftHeaderH = 12;
            float rowH = Math.Min(20, (availableH - dayHeaderH - shiftHeaderH) / rowCount);
            if (rowH < 11) rowH = 11;

            // === 일자 헤더행 (날짜 번호, 3칸 병합) ===
            float cx = x + fixedW;
            // 고정 컬럼 헤더 (일자 헤더 높이만큼 병합)
            float totalHeaderH = dayHeaderH + shiftHeaderH;

            // 고정 컬럼 헤더 그리기
            float hx = x;
            string[] fixedHeaders = { "NO", "점검 항목", "점검 기준", "방법", "구분" };
            float[] fixedWidths = { colNo, colItem, colStd, colMethod, colType };
            for (int c = 0; c < 5; c++)
            {
                g.DrawRectangle(penBold, hx, y, fixedWidths[c], totalHeaderH);
                g.DrawString(fixedHeaders[c], fontHeaderBold, brushBlack,
                    new RectangleF(hx, y, fixedWidths[c], totalHeaderH), sfCenter);
                hx += fixedWidths[c];
            }

            // 일자 헤더 (3칸 병합)
            cx = x + fixedW;
            for (int d = startDay; d <= endDay; d++)
            {
                float dayW = shiftColW * 3;
                g.DrawRectangle(penBlack, cx, y, dayW, dayHeaderH);
                g.DrawString(d.ToString(), fontHeaderBold, brushBlack,
                    new RectangleF(cx, y, dayW, dayHeaderH), sfCenter);
                cx += dayW;
            }

            // 교대 헤더 (아/점/저)
            y += dayHeaderH;
            cx = x + fixedW;
            for (int d = startDay; d <= endDay; d++)
            {
                for (int s = 0; s < 3; s++)
                {
                    g.DrawRectangle(penBlack, cx, y, shiftColW, shiftHeaderH);
                    g.DrawString(SHIFT_NAMES[s], fontShift, brushBlack,
                        new RectangleF(cx, y, shiftColW, shiftHeaderH), sfCenter);
                    cx += shiftColW;
                }
            }
            y += shiftHeaderH;

            // === 데이터행 ===
            for (int r = 0; r < rowCount; r++)
            {
                hx = x;

                // 고정 컬럼
                string[] cellValues = {
                    (r + 1).ToString(),
                    _items[r][0],
                    _items[r][1],
                    _items[r][2],
                    _items[r][3]
                };
                for (int c = 0; c < 5; c++)
                {
                    g.DrawRectangle(penBlack, hx, y, fixedWidths[c], rowH);
                    var fmt = (c == 0 || c >= 3) ? sfCenter : sfLeft;
                    var f = (c <= 1) ? fontCellBold : fontCell;
                    g.DrawString(cellValues[c], f, brushBlack,
                        new RectangleF(hx + 2, y, fixedWidths[c] - 4, rowH), fmt);
                    hx += fixedWidths[c];
                }

                // 교대 컬럼
                string itemKey = $"Item{r + 1}";
                cx = x + fixedW;
                for (int d = startDay; d <= endDay; d++)
                {
                    for (int s = 0; s < 3; s++)
                    {
                        g.DrawRectangle(penBlack, cx, y, shiftColW, rowH);

                        string dataKey = $"Day{d}_{SHIFT_KEYS[s]}";
                        string val = "";
                        if (allData.ContainsKey(itemKey) && allData[itemKey].ContainsKey(dataKey))
                            val = allData[itemKey][dataKey];

                        if (!string.IsNullOrEmpty(val))
                        {
                            var brush = val == "O" ? brushGreen : (val == "X" ? brushRed : brushBlack);
                            g.DrawString(val, fontCellBold, brush,
                                new RectangleF(cx, y, shiftColW, rowH), sfCenter);
                        }
                        cx += shiftColW;
                    }
                }
                y += rowH;
            }

            // === 서명란 ===
            y += 8;
            g.DrawString($"생산 관리자 (SIGN): {txtProdSign.Text}", fontHeader, brushBlack, x, y);
            g.DrawString($"품질 관리자 (SIGN): {txtQualSign.Text}", fontHeader, brushBlack, x + 220, y);

            // 폰트 해제
            fontTitle.Dispose();
            fontHeader.Dispose();
            fontHeaderBold.Dispose();
            fontCell.Dispose();
            fontCellBold.Dispose();
            fontShift.Dispose();
            penBlack.Dispose();
            penBold.Dispose();
            brushGreen.Dispose();
            brushRed.Dispose();

            // 다음 페이지
            _printRange++;
            e.HasMorePages = (_printRange < 3);
        }

        #endregion
    }
}

