        #region Grid 설정

        private void SetupGrid()
        {
            _loading = true;
            dgv.Columns.Clear();
            dgv.Rows.Clear();

            // 고정 컬럼
            AddColumn("colNo", "NO", 22, true);
            AddColumn("colItem", "점검 항목", 110, false);
            AddColumn("colStandard", "점검 기준", 80, false);
            AddColumn("colMethod", "방법", 38, false);
            AddColumn("colType", "구분", 35, false);

            // 범위별 일자 × 교대 컬럼
            GetRangeStartEnd(out int startDay, out int endDay);
            int daysInMonth = DateTime.DaysInMonth(_currentMonth.Year, _currentMonth.Month);

            for (int d = startDay; d <= endDay; d++)
            {
                for (int s = 0; s < 3; s++)
                {
                    var col = new DataGridViewTextBoxColumn();
                    col.Name = $"colDay{d}_{SHIFT_KEYS[s]}";
                    col.HeaderText = $"{d}\n{SHIFT_NAMES[s]}";
                    col.Width = 18;
                    col.MinimumWidth = 16;
                    col.ReadOnly = true;
                    col.SortMode = DataGridViewColumnSortMode.NotSortable;
                    col.DefaultCellStyle.Font = new Font("맑은 고딕", 7.5F, FontStyle.Bold);

                    // 교대별 배경색 구분
                    if (d > daysInMonth)
                    {
                        col.DefaultCellStyle.BackColor = Color.FromArgb(50, 50, 50);
                    }
                    else if (s == 0)
                        col.DefaultCellStyle.BackColor = Color.FromArgb(38, 38, 48); // 아침
                    else if (s == 1)
                        col.DefaultCellStyle.BackColor = Color.FromArgb(38, 44, 38); // 점심
                    else
                        col.DefaultCellStyle.BackColor = Color.FromArgb(44, 38, 38); // 저녁

                    dgv.Columns.Add(col);
                }
            }

            // 항목 행 추가
            for (int i = 0; i < _items.Count; i++)
            {
                int rowIdx = dgv.Rows.Add();
                var row = dgv.Rows[rowIdx];
                row.Cells["colNo"].Value = (i + 1).ToString();
                row.Cells["colItem"].Value = _items[i][0];
                row.Cells["colStandard"].Value = _items[i][1];
                row.Cells["colMethod"].Value = _items[i][2];
                row.Cells["colType"].Value = _items[i][3];
                row.Cells["colItem"].Style.Alignment = DataGridViewContentAlignment.MiddleLeft;
                row.Cells["colStandard"].Style.Alignment = DataGridViewContentAlignment.MiddleLeft;
            }

            // 고정 컬럼 (스크롤 시 왼쪽 고정)
            dgv.Columns["colType"].Frozen = true;

            // Auto-fill grid rows to remove empty space
            AdjustGridRowHeight();

            _loading = false;
        }

        /// <summary>
        /// Adjust row height to fill available grid space
        /// </summary>
        private void AdjustGridRowHeight()
        {
            if (dgv.Rows.Count == 0) return;
            int availableH = dgv.ClientSize.Height - dgv.ColumnHeadersHeight;
            if (availableH <= 0) return;
            int rowH = availableH / dgv.Rows.Count;
            if (rowH < 24) rowH = 24;
            foreach (DataGridViewRow row in dgv.Rows)
                row.Height = rowH;

            // Auto-fill date columns to use remaining width
            AdjustDateColumnWidth();
        }

        /// <summary>
        /// Distribute remaining horizontal space to date columns evenly
        /// </summary>
        private void AdjustDateColumnWidth()
        {
            // Calculate fixed columns total width
            int fixedW = 0;
            int dateColCount = 0;
            foreach (DataGridViewColumn col in dgv.Columns)
            {
                if (col.Name.StartsWith("colDay"))
                    dateColCount++;
                else
                    fixedW += col.Width;
            }
            if (dateColCount == 0) return;

            int availableW = dgv.ClientSize.Width - fixedW - SystemInformation.VerticalScrollBarWidth;
            if (availableW <= 0) return;
            int dateW = availableW / dateColCount;
            if (dateW < 16) dateW = 16;

            foreach (DataGridViewColumn col in dgv.Columns)
            {
                if (col.Name.StartsWith("colDay"))
                    col.Width = dateW;
            }
        }

        private void AddColumn(string name, string header, int width, bool readOnly)
        {
            var col = new DataGridViewTextBoxColumn();
            col.Name = name;
            col.HeaderText = header;
            col.Width = width;
            col.ReadOnly = readOnly;
            col.SortMode = DataGridViewColumnSortMode.NotSortable;
            dgv.Columns.Add(col);
        }

