        #region 월 변경

        private void DtpMonth_ValueChanged(object sender, EventArgs e)
        {
            var newMonth = new DateTime(dtpMonth.Value.Year, dtpMonth.Value.Month, 1);
            if (newMonth == _currentMonth) return;

            _currentMonth = newMonth;

            // 현재 월이면 오늘 기준 자동 전환
            if (_currentMonth.Year == DateTime.Now.Year && _currentMonth.Month == DateTime.Now.Month)
                AutoDetectRange();

            SetupGrid();
            LoadData();
            UpdateRangeButtons();
        }

