        private void BtnDeleteItem_Click(object sender, EventArgs e)
        {
            if (dgv.CurrentRow == null) return;
            int rowIdx = dgv.CurrentRow.Index;
            if (rowIdx < 0 || rowIdx >= dgv.Rows.Count) return;

            string itemName = dgv.Rows[rowIdx].Cells["colItem"].Value?.ToString() ?? "";
            var result = MessageBox.Show(
                $"항목 {rowIdx + 1} ({itemName})을(를) 삭제하시겠습니까?\n\n※ 해당 항목의 모든 월별 체크 데이터도 영향을 받습니다.",
                "항목 삭제 확인", MessageBoxButtons.YesNo, MessageBoxIcon.Warning);

            if (result != DialogResult.Yes) return;

            _loading = true;
            dgv.Rows.RemoveAt(rowIdx);
            for (int i = 0; i < dgv.Rows.Count; i++)
                dgv.Rows[i].Cells["colNo"].Value = (i + 1).ToString();
            _loading = false;

            SyncItemsFromGrid();
            SaveItems();
            SaveData();

            LogCheckAction(rowIdx + 1, itemName, 0, "", itemName, "삭제됨");
            RefreshPhotoList();
        }

