using System;
using System.Collections.Generic;
using System.Drawing;
using System.Drawing.Printing;
using System.IO;
using System.Linq;
using System.Windows.Forms;

namespace WeldMonitor3
{
    public partial class _FrmDailyCheck : Form
    {
        [System.Runtime.InteropServices.DllImport("Gdi32.dll", EntryPoint = "CreateRoundRectRgn")]
        private static extern IntPtr CreateRoundRectRgn(
            int nLeftRect, int nTopRect, int nRightRect, int nBottomRect,
            int nWidthEllipse, int nHeightEllipse);

        // 기본 점검항목 (하체부 DL3 워크시트 기준)
        // [0]=점검항목, [1]=점검기준, [2]=점검방법, [3]=구분
        private static readonly string[][] DEFAULT_ITEMS = new string[][]
        {
            new[] { "AIR 전동 고압 호스 압력",   "4~6 kgf/㎠",        "확인",   "1일/SHIFT" },
            new[] { "유닛 정위치 이동거리",       "무부하 움직임 확인", "확인",   "✓" },
            new[] { "시간제한 변경작동",           "변경 이상 여부",    "확인",   "✓" },
            new[] { "위치제한기 움직임",           "이상 여부",         "확인",   "✓" },
            new[] { "방전소음기 움직임",           "이상 여부",         "확인",   "✓" },
            new[] { "전류(1호기)",                "12~18 KA",          "용접기", "✓" },
            new[] { "사이클타임(1호기)",           "17~23 CYCLE",       "용접기", "✓" },
            new[] { "가압력(1호기)",              "4~6 Kgf/㎠",        "용접기", "✓" },
            new[] { "통전시간(1호기)",            "10~30 초",           "용접기", "✓" },
            new[] { "전류(2호기)",                "12~18 KA",          "용접기", "✓" },
            new[] { "사이클타임(2호기)",           "15~21 CYCLE",       "용접기", "✓" },
            new[] { "가압력(2호기)",              "4~6 Kgf/㎠",        "용접기", "✓" },
            new[] { "통전시간(2호기)",            "10~30 초",           "용접기", "✓" },
        };

        // 동적 점검항목 리스트 (파일에서 로드/저장)
        private List<string[]> _items = new List<string[]>();

        private string _basePath;
        private string _photoPath;
        private DateTime _currentMonth;
        private bool _loading = false;
        private int _currentRange = 0;  // 0=1~10, 1=11~20, 2=21~31
        private int _printRange = 0;    // PDF 인쇄용 페이지 카운터

        private static readonly string[] SHIFT_KEYS = { "M", "A", "E" };
        private static readonly string[] SHIFT_NAMES = { "아", "점", "저" };
        private static readonly string[] SHIFT_FULL = { "아침", "점심", "저녁" };
        private const int FIXED_COL_COUNT = 5;  // NO, 항목, 기준, 방법, 구분

        public _FrmDailyCheck()
        {
            InitializeComponent();
            LayoutHeader();
            ThemeManager.ApplyDarkTheme(this);
            StyleControls();

            _basePath = Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "DailyCheck");
            _photoPath = Path.Combine(_basePath, "Photos");
            if (!Directory.Exists(_photoPath))
                Directory.CreateDirectory(_photoPath);

            _currentMonth = new DateTime(DateTime.Now.Year, DateTime.Now.Month, 1);
            dtpMonth.Value = _currentMonth;

            // 오늘 날짜 기준 범위 자동 선택
            AutoDetectRange();
            LoadItems();

            // 이벤트 연결
            dtpMonth.ValueChanged += DtpMonth_ValueChanged;
            dgv.CellClick += Dgv_CellClick;
            dgv.CellEndEdit += Dgv_CellEndEdit;
            dgv.SelectionChanged += Dgv_SelectionChanged;
            btnSave.Click += BtnSave_Click;
            btnPdf.Click += BtnPdf_Click;
            btnSetPhoto.Click += BtnSetPhoto_Click;
            btnAddItem.Click += BtnAddItem_Click;
            btnDeleteItem.Click += BtnDeleteItem_Click;
            btnClose.Click += (s, e) => this.Close();
            btnRange1.Click += (s, e) => SetRange(0);
            btnRange2.Click += (s, e) => SetRange(1);
            btnRange3.Click += (s, e) => SetRange(2);

            // 헤더 텍스트 변경 시 자동 저장
            foreach (var txt in new[] { txtDept, txtSupervisor, txtEquipName, txtQuality,
                                        txtEquipNo, txtWriter, txtReviewer, txtApprover,
                                        txtProdSign, txtQualSign })
            {
                txt.Leave += (s, e) => SaveData();
            }

            SetupGrid();
            LoadData();
            UpdateRangeButtons();
            RefreshPhotoList();

            this.Shown += (s, e) => { LayoutHeaderRow2(); AdjustGridRowHeight(); RefreshPhotoList(); };
            this.Resize += (s, e) => { LayoutHeaderRow2(); AdjustGridRowHeight(); RefreshPhotoList(); };
        }

        /// <summary>
        /// Position header controls properly (Designer keeps resetting to 0,0)
        /// </summary>
        private void LayoutHeader()
        {
            // Row 1: fixed positions
            panelHeaderRow1.Height = 34;
            lblTitle.Location = new Point(8, 4);
            dtpMonth.Location = new Point(340, 2);
            dtpMonth.Size = new Size(130, 28);
            btnRange1.Location = new Point(480, 2);
            btnRange1.Size = new Size(65, 28);
            btnRange2.Location = new Point(548, 2);
            btnRange2.Size = new Size(68, 28);
            btnRange3.Location = new Point(619, 2);
            btnRange3.Size = new Size(68, 28);

            // Row 2: dynamic layout
            panelHeaderRow2.Height = 28;
            panelHeader.Height = 66;
            LayoutHeaderRow2();
        }

        /// <summary>
        /// Auto-layout header row 2 fields evenly across available width
        /// </summary>
        private void LayoutHeaderRow2()
        {
            var fields = new[] {
                (lbl: lblDept, txt: txtDept, label: "관리부서:"),
                (lbl: lblSupervisor, txt: txtSupervisor, label: "관리감독:"),
                (lbl: lblEquipName, txt: txtEquipName, label: "설비명칭:"),
                (lbl: lblEquipNo, txt: txtEquipNo, label: "설비번호:"),
                (lbl: lblQuality, txt: txtQuality, label: "품질:"),
                (lbl: lblWriter, txt: txtWriter, label: "작성:"),
                (lbl: lblReviewer, txt: txtReviewer, label: "검토:"),
                (lbl: lblApprover, txt: txtApprover, label: "승인:"),
            };

            int totalW = panelHeaderRow2.ClientSize.Width;
            int gap = 4;
            int sectionW = (totalW - gap * fields.Length) / fields.Length;
            int x = gap;
            int y = 2;

            foreach (var f in fields)
            {
                f.lbl.Text = f.label;
                f.lbl.Font = new Font("맑은 고딕", 7.5F);
                f.lbl.AutoSize = false;
                int lblW = TextRenderer.MeasureText(f.label, f.lbl.Font).Width + 2;
                f.lbl.Location = new Point(x, y + 3);
                f.lbl.Size = new Size(lblW, 18);

                f.txt.Font = new Font("맑은 고딕", 7.5F);
                f.txt.Location = new Point(x + lblW, y);
                f.txt.Size = new Size(sectionW - lblW, 22);

                x += sectionW + gap;
            }
        }

        /// <summary>
        /// 오늘 날짜 기준 범위 자동 선택
        /// </summary>
        private void AutoDetectRange()
        {
            int today = DateTime.Now.Day;
            if (today <= 10) _currentRange = 0;
            else if (today <= 20) _currentRange = 1;
            else _currentRange = 2;
        }

        /// <summary>
        /// 다크테마 버튼 스타일 적용
        /// </summary>
        private void StyleControls()
        {
            var allButtons = new List<Button>();
            foreach (Control c in panelBottom.Controls)
            {
                if (c is Button btn) allButtons.Add(btn);
            }
            allButtons.AddRange(new[] { btnRange1, btnRange2, btnRange3, btnSetPhoto });

            foreach (var btn in allButtons)
            {
                btn.FlatAppearance.BorderColor = ThemeManager.DarkTheme.BorderColor;
                btn.FlatAppearance.BorderSize = 1;
                btn.Region = Region.FromHrgn(CreateRoundRectRgn(0, 0, btn.Width, btn.Height, 8, 8));
                btn.MouseEnter += (s, e) => ((Button)s).BackColor = pColor.Theme.buttonHover;
                btn.MouseLeave += (s, e) =>
                {
                    var b = (Button)s;
                    if (b == btnRange1 || b == btnRange2 || b == btnRange3)
                        UpdateRangeButtons();
                    else
                        b.BackColor = ThemeManager.DarkTheme.BackgroundLight;
                };
            }
        }

        /// <summary>
        /// 범위 버튼 활성 상태 표시
        /// </summary>
        private void UpdateRangeButtons()
        {
            var rangeButtons = new[] { btnRange1, btnRange2, btnRange3 };
            for (int i = 0; i < 3; i++)
            {
                if (i == _currentRange)
                {
                    rangeButtons[i].BackColor = Color.FromArgb(0, 90, 158);
                    rangeButtons[i].ForeColor = Color.White;
                }
                else
                {
                    rangeButtons[i].BackColor = ThemeManager.DarkTheme.BackgroundLight;
                    rangeButtons[i].ForeColor = ThemeManager.DarkTheme.TextPrimary;
                }
            }
        }

        /// <summary>
        /// 범위 전환
        /// </summary>
        private void SetRange(int range)
        {
            if (_currentRange == range) return;
            _currentRange = range;
            SetupGrid();
            LoadData();
            UpdateRangeButtons();
        }

        /// <summary>
        /// 현재 범위의 시작/끝 일자 계산
        /// </summary>
        private void GetRangeStartEnd(out int start, out int end)
        {
            int daysInMonth = DateTime.DaysInMonth(_currentMonth.Year, _currentMonth.Month);
            switch (_currentRange)
            {
                case 0: start = 1; end = 10; break;
                case 1: start = 11; end = 20; break;
                default: start = 21; end = Math.Min(31, daysInMonth); break;
            }
        }

        /// <summary>
        /// 지정 범위의 시작/끝 일자 계산
        /// </summary>
        private void GetRangeStartEnd(int range, out int start, out int end)
        {
            int daysInMonth = DateTime.DaysInMonth(_currentMonth.Year, _currentMonth.Month);
            switch (range)
            {
                case 0: start = 1; end = 10; break;
                case 1: start = 11; end = 20; break;
                default: start = 21; end = Math.Min(31, daysInMonth); break;
            }
        }

        #region 점검항목 관리 (파일 기반)

        private string GetItemsFilePath() => Path.Combine(_basePath, "items.ini");

        private void LoadItems()
        {
            _items.Clear();
            string filePath = GetItemsFilePath();

            if (File.Exists(filePath))
            {
                try
                {
                    foreach (var line in File.ReadAllLines(filePath, System.Text.Encoding.UTF8))
                    {
                        string trimmed = line.Trim();
                        if (string.IsNullOrEmpty(trimmed) || trimmed.StartsWith("#")) continue;
                        string[] parts = trimmed.Split('\t');
                        if (parts.Length >= 4)
                            _items.Add(new[] { parts[0], parts[1], parts[2], parts[3] });
                    }
                }
                catch (Exception ex)
                {
                    Logger.Error($"[일상점검] 항목 로드 실패: {ex.Message}");
                }
            }

            if (_items.Count == 0)
            {
                foreach (var item in DEFAULT_ITEMS)
                    _items.Add((string[])item.Clone());
                SaveItems();
            }
        }

        private void SaveItems()
        {
            try
            {
                if (!Directory.Exists(_basePath))
                    Directory.CreateDirectory(_basePath);

                string filePath = GetItemsFilePath();
                using (var sw = new StreamWriter(filePath, false, System.Text.Encoding.UTF8))
                {
                    sw.WriteLine("# 점검항목 설정 (탭 구분: 점검항목\\t점검기준\\t점검방법\\t구분)");
                    foreach (var item in _items)
                        sw.WriteLine($"{item[0]}\t{item[1]}\t{item[2]}\t{item[3]}");
                }
            }
            catch (Exception ex)
            {
                Logger.Error($"[일상점검] 항목 저장 실패: {ex.Message}");
            }
        }

        private void SyncItemsFromGrid()
        {
            _items.Clear();
            for (int i = 0; i < dgv.Rows.Count; i++)
            {
                var row = dgv.Rows[i];
                string item = row.Cells["colItem"].Value?.ToString() ?? "";
                string standard = row.Cells["colStandard"].Value?.ToString() ?? "";
                string method = row.Cells["colMethod"].Value?.ToString() ?? "";
                string type = row.Cells["colType"].Value?.ToString() ?? "";
                _items.Add(new[] { item, standard, method, type });
            }
        }

