#region PDF 출력 (3페이지: 범위별)

/// <summary>
/// Draw photo thumbnails in 7-col grid for PDF (only on first page)
/// </summary>
private float DrawPhotoGrid(Graphics g, float x, float y, float pageW, int itemCount)
{
    if (_printRange > 0) return y;  // photos only on first page

    const int COLS = 7;
    int count = Math.Min(itemCount, 14);
    int rows = (count + COLS - 1) / COLS;

    float gap = 3;
    float lblH = 10;
    float cellW = (pageW - gap * (COLS + 1)) / COLS;
    float imgH = 50;
    float rowH = lblH + imgH + gap;

    var fontLbl = new Font("맑은 고딕", 5.5f);
    var penBorder = new Pen(Color.Gray, 0.3f);
    var sfLeft = new StringFormat { Alignment = StringAlignment.Near, LineAlignment = StringAlignment.Center, Trimming = StringTrimming.EllipsisCharacter };

    for (int i = 0; i < count; i++)
    {
        int col = i % COLS;
        int row = i / COLS;
        float cx = x + gap + col * (cellW + gap);
        float cy = y + row * rowH;

        // Item label
        string label = $"{i + 1}. {_items[i][0]}";
        g.DrawString(label, fontLbl, Brushes.Black, new RectangleF(cx, cy, cellW, lblH), sfLeft);

        // Photo image
        RectangleF imgRect = new RectangleF(cx, cy + lblH, cellW, imgH);
        g.DrawRectangle(penBorder, cx, cy + lblH, cellW, imgH);

        Image img = LoadPhotoImage(i);
        if (img != null)
        {
            // Fit image maintaining aspect ratio
            float scale = Math.Min(cellW / img.Width, imgH / img.Height);
            float drawW = img.Width * scale;
            float drawH = img.Height * scale;
            float drawX = cx + (cellW - drawW) / 2;
            float drawY = cy + lblH + (imgH - drawH) / 2;
            g.DrawImage(img, drawX, drawY, drawW, drawH);
            img.Dispose();
        }
    }

    fontLbl.Dispose();
    penBorder.Dispose();

    return y + rows * rowH + gap;
}

/// <summary>
/// Load photo image by item index (returns null if not found)
/// </summary>
private Image LoadPhotoImage(int itemIndex)
{
    string prefix = (itemIndex + 1).ToString("D2");
    string[] exts = { ".jpg", ".jpeg", ".png", ".bmp", ".gif" };
    foreach (var ext in exts)
    {
        string path = Path.Combine(_photoPath, prefix + ext);
        if (File.Exists(path))
        {
            try
            {
                using (var fs = new FileStream(path, FileMode.Open, FileAccess.Read))
                    return Image.FromStream(new MemoryStream(File.ReadAllBytes(path)));
            }
            catch { }
        }
    }
    return null;
}

