using System;
using System.Collections.Generic;
using System.Drawing;
using System.Drawing.Printing;
using System.IO;
using System.Linq;
using System.Windows.Forms;

namespace WeldMonitor3
{
    public partial class _FrmDailyCheck : Form
    {
        [System.Runtime.InteropServices.DllImport("Gdi32.dll", EntryPoint = "CreateRoundRectRgn")]
        private static extern IntPtr CreateRoundRectRgn(
            int nLeftRect, int nTopRect, int nRightRect, int nBottomRect,
            int nWidthEllipse, int nHeightEllipse);

        // 기본 점검항목 (하체부 DL3 워크시트 기준)
        // [0]=점검항목, [1]=점검기준, [2]=점검방법, [3]=구분
        private static readonly string[][] DEFAULT_ITEMS = new string[][]
        {
            new[] { "AIR 전동 고압 호스 압력",   "4~6 kgf/㎠",        "확인",   "1일/SHIFT" },
            new[] { "유닛 정위치 이동거리",       "무부하 움직임 확인", "확인",   "✓" },
            new[] { "시간제한 변경작동",           "변경 이상 여부",    "확인",   "✓" },
            new[] { "위치제한기 움직임",           "이상 여부",         "확인",   "✓" },
            new[] { "방전소음기 움직임",           "이상 여부",         "확인",   "✓" },
            new[] { "전류(1호기)",                "12~18 KA",          "용접기", "✓" },
            new[] { "사이클타임(1호기)",           "17~23 CYCLE",       "용접기", "✓" },
            new[] { "가압력(1호기)",              "4~6 Kgf/㎠",        "용접기", "✓" },
            new[] { "통전시간(1호기)",            "10~30 초",           "용접기", "✓" },
            new[] { "전류(2호기)",                "12~18 KA",          "용접기", "✓" },
            new[] { "사이클타임(2호기)",           "15~21 CYCLE",       "용접기", "✓" },
            new[] { "가압력(2호기)",              "4~6 Kgf/㎠",        "용접기", "✓" },
            new[] { "통전시간(2호기)",            "10~30 초",           "용접기", "✓" },
        };

        // 동적 점검항목 리스트 (파일에서 로드/저장)
        private List<string[]> _items = new List<string[]>();

        private string _basePath;
        private string _photoPath;
        private DateTime _currentMonth;
        private bool _loading = false;
        private int _currentRange = 0;  // 0=1~10, 1=11~20, 2=21~31
        private int _printRange = 0;    // PDF 인쇄용 페이지 카운터

        private static readonly string[] SHIFT_KEYS = { "M", "A", "E" };
        private static readonly string[] SHIFT_NAMES = { "아", "점", "저" };
        private static readonly string[] SHIFT_FULL = { "아침", "점심", "저녁" };
        private const int FIXED_COL_COUNT = 5;  // NO, 항목, 기준, 방법, 구분

        public _FrmDailyCheck()
        {
            InitializeComponent();
            LayoutHeader();
            ThemeManager.ApplyDarkTheme(this);
            StyleControls();

            _basePath = Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "DailyCheck");
            _photoPath = Path.Combine(_basePath, "Photos");
            if (!Directory.Exists(_photoPath))
                Directory.CreateDirectory(_photoPath);

            _currentMonth = new DateTime(DateTime.Now.Year, DateTime.Now.Month, 1);
            dtpMonth.Value = _currentMonth;

            // 오늘 날짜 기준 범위 자동 선택
            AutoDetectRange();
            LoadItems();

            // 이벤트 연결
            dtpMonth.ValueChanged += DtpMonth_ValueChanged;
            dgv.CellClick += Dgv_CellClick;
            dgv.CellEndEdit += Dgv_CellEndEdit;
            dgv.SelectionChanged += Dgv_SelectionChanged;
            btnSave.Click += BtnSave_Click;
            btnPdf.Click += BtnPdf_Click;
            btnSetPhoto.Click += BtnSetPhoto_Click;
            btnAddItem.Click += BtnAddItem_Click;
            btnDeleteItem.Click += BtnDeleteItem_Click;
            btnClose.Click += (s, e) => this.Close();
            btnRange1.Click += (s, e) => SetRange(0);
            btnRange2.Click += (s, e) => SetRange(1);
            btnRange3.Click += (s, e) => SetRange(2);

            // 헤더 텍스트 변경 시 자동 저장
            foreach (var txt in new[] { txtDept, txtSupervisor, txtEquipName, txtQuality,
                                        txtEquipNo, txtWriter, txtReviewer, txtApprover,
                                        txtProdSign, txtQualSign })
            {
                txt.Leave += (s, e) => SaveData();
            }

            SetupGrid();
            LoadData();
            UpdateRangeButtons();
            RefreshPhotoList();

            this.Shown += (s, e) => { LayoutHeaderRow2(); AdjustGridRowHeight(); RefreshPhotoList(); };
            this.Resize += (s, e) => { LayoutHeaderRow2(); AdjustGridRowHeight(); RefreshPhotoList(); };
        }

        /// <summary>
        /// Position header controls properly (Designer keeps resetting to 0,0)
        /// </summary>
        private void LayoutHeader()
        {
            // Row 1: fixed positions
            panelHeaderRow1.Height = 34;
            lblTitle.Location = new Point(8, 4);
            dtpMonth.Location = new Point(340, 2);
            dtpMonth.Size = new Size(130, 28);
            btnRange1.Location = new Point(480, 2);
            btnRange1.Size = new Size(65, 28);
            btnRange2.Location = new Point(548, 2);
            btnRange2.Size = new Size(68, 28);
            btnRange3.Location = new Point(619, 2);
            btnRange3.Size = new Size(68, 28);

            // Row 2: dynamic layout
            panelHeaderRow2.Height = 28;
            panelHeader.Height = 66;
            LayoutHeaderRow2();
        }

        /// <summary>
        /// Auto-layout header row 2 fields evenly across available width
        /// </summary>
        private void LayoutHeaderRow2()
        {
            var fields = new[] {
                (lbl: lblDept, txt: txtDept, label: "관리부서:"),
                (lbl: lblSupervisor, txt: txtSupervisor, label: "관리감독:"),
                (lbl: lblEquipName, txt: txtEquipName, label: "설비명칭:"),
                (lbl: lblEquipNo, txt: txtEquipNo, label: "설비번호:"),
                (lbl: lblQuality, txt: txtQuality, label: "품질:"),
                (lbl: lblWriter, txt: txtWriter, label: "작성:"),
                (lbl: lblReviewer, txt: txtReviewer, label: "검토:"),
                (lbl: lblApprover, txt: txtApprover, label: "승인:"),
            };

            int totalW = panelHeaderRow2.ClientSize.Width;
            int gap = 4;
            int sectionW = (totalW - gap * fields.Length) / fields.Length;
            int x = gap;
            int y = 2;

            foreach (var f in fields)
            {
                f.lbl.Text = f.label;
                f.lbl.Font = new Font("맑은 고딕", 7.5F);
                f.lbl.AutoSize = false;
                int lblW = TextRenderer.MeasureText(f.label, f.lbl.Font).Width + 2;
                f.lbl.Location = new Point(x, y + 3);
                f.lbl.Size = new Size(lblW, 18);

                f.txt.Font = new Font("맑은 고딕", 7.5F);
                f.txt.Location = new Point(x + lblW, y);
                f.txt.Size = new Size(sectionW - lblW, 22);

                x += sectionW + gap;
            }
        }

        /// <summary>
        /// 오늘 날짜 기준 범위 자동 선택
        /// </summary>
        private void AutoDetectRange()
        {
            int today = DateTime.Now.Day;
            if (today <= 10) _currentRange = 0;
            else if (today <= 20) _currentRange = 1;
            else _currentRange = 2;
        }

        /// <summary>
        /// 다크테마 버튼 스타일 적용
        /// </summary>
        private void StyleControls()
        {
            var allButtons = new List<Button>();
            foreach (Control c in panelBottom.Controls)
            {
                if (c is Button btn) allButtons.Add(btn);
            }
            allButtons.AddRange(new[] { btnRange1, btnRange2, btnRange3, btnSetPhoto });

            foreach (var btn in allButtons)
            {
                btn.FlatAppearance.BorderColor = ThemeManager.DarkTheme.BorderColor;
                btn.FlatAppearance.BorderSize = 1;
                btn.Region = Region.FromHrgn(CreateRoundRectRgn(0, 0, btn.Width, btn.Height, 8, 8));
                btn.MouseEnter += (s, e) => ((Button)s).BackColor = pColor.Theme.buttonHover;
                btn.MouseLeave += (s, e) =>
                {
                    var b = (Button)s;
                    if (b == btnRange1 || b == btnRange2 || b == btnRange3)
                        UpdateRangeButtons();
                    else
                        b.BackColor = ThemeManager.DarkTheme.BackgroundLight;
                };
            }
        }

        /// <summary>
        /// 범위 버튼 활성 상태 표시
        /// </summary>
        private void UpdateRangeButtons()
        {
            var rangeButtons = new[] { btnRange1, btnRange2, btnRange3 };
            for (int i = 0; i < 3; i++)
            {
                if (i == _currentRange)
                {
                    rangeButtons[i].BackColor = Color.FromArgb(0, 90, 158);
                    rangeButtons[i].ForeColor = Color.White;
                }
                else
                {
                    rangeButtons[i].BackColor = ThemeManager.DarkTheme.BackgroundLight;
                    rangeButtons[i].ForeColor = ThemeManager.DarkTheme.TextPrimary;
                }
            }
        }

        /// <summary>
        /// 범위 전환
        /// </summary>
        private void SetRange(int range)
        {
            if (_currentRange == range) return;
            _currentRange = range;
            SetupGrid();
            LoadData();
            UpdateRangeButtons();
        }

        /// <summary>
        /// 현재 범위의 시작/끝 일자 계산
        /// </summary>
        private void GetRangeStartEnd(out int start, out int end)
        {
            int daysInMonth = DateTime.DaysInMonth(_currentMonth.Year, _currentMonth.Month);
            switch (_currentRange)
            {
                case 0: start = 1; end = 10; break;
                case 1: start = 11; end = 20; break;
                default: start = 21; end = Math.Min(31, daysInMonth); break;
            }
        }

        /// <summary>
        /// 지정 범위의 시작/끝 일자 계산
        /// </summary>
        private void GetRangeStartEnd(int range, out int start, out int end)
        {
            int daysInMonth = DateTime.DaysInMonth(_currentMonth.Year, _currentMonth.Month);
            switch (range)
            {
                case 0: start = 1; end = 10; break;
                case 1: start = 11; end = 20; break;
                default: start = 21; end = Math.Min(31, daysInMonth); break;
            }
        }

        #region 점검항목 관리 (파일 기반)

        private string GetItemsFilePath() => Path.Combine(_basePath, "items.ini");

        private void LoadItems()
        {
            _items.Clear();
            string filePath = GetItemsFilePath();

            if (File.Exists(filePath))
            {
                try
                {
                    foreach (var line in File.ReadAllLines(filePath, System.Text.Encoding.UTF8))
                    {
                        string trimmed = line.Trim();
                        if (string.IsNullOrEmpty(trimmed) || trimmed.StartsWith("#")) continue;
                        string[] parts = trimmed.Split('\t');
                        if (parts.Length >= 4)
                            _items.Add(new[] { parts[0], parts[1], parts[2], parts[3] });
                    }
                }
                catch (Exception ex)
                {
                    Logger.Error($"[일상점검] 항목 로드 실패: {ex.Message}");
                }
            }

            if (_items.Count == 0)
            {
                foreach (var item in DEFAULT_ITEMS)
                    _items.Add((string[])item.Clone());
                SaveItems();
            }
        }

        private void SaveItems()
        {
            try
            {
                if (!Directory.Exists(_basePath))
                    Directory.CreateDirectory(_basePath);

                string filePath = GetItemsFilePath();
                using (var sw = new StreamWriter(filePath, false, System.Text.Encoding.UTF8))
                {
                    sw.WriteLine("# 점검항목 설정 (탭 구분: 점검항목\\t점검기준\\t점검방법\\t구분)");
                    foreach (var item in _items)
                        sw.WriteLine($"{item[0]}\t{item[1]}\t{item[2]}\t{item[3]}");
                }
            }
            catch (Exception ex)
            {
                Logger.Error($"[일상점검] 항목 저장 실패: {ex.Message}");
            }
        }

        private void SyncItemsFromGrid()
        {
            _items.Clear();
            for (int i = 0; i < dgv.Rows.Count; i++)
            {
                var row = dgv.Rows[i];
                string item = row.Cells["colItem"].Value?.ToString() ?? "";
                string standard = row.Cells["colStandard"].Value?.ToString() ?? "";
                string method = row.Cells["colMethod"].Value?.ToString() ?? "";
                string type = row.Cells["colType"].Value?.ToString() ?? "";
                _items.Add(new[] { item, standard, method, type });
            }
        }

        private void BtnAddItem_Click(object sender, EventArgs e)
        {
            _loading = true;
            int newNo = dgv.Rows.Count + 1;
            int rowIdx = dgv.Rows.Add();
            var row = dgv.Rows[rowIdx];
            row.Cells["colNo"].Value = newNo.ToString();
            row.Cells["colItem"].Value = "(새 항목)";
            row.Cells["colStandard"].Value = "";
            row.Cells["colMethod"].Value = "확인";
            row.Cells["colType"].Value = "✓";
            row.Cells["colItem"].Style.Alignment = DataGridViewContentAlignment.MiddleLeft;
            row.Cells["colStandard"].Style.Alignment = DataGridViewContentAlignment.MiddleLeft;
            _loading = false;

            SyncItemsFromGrid();
            SaveItems();
            SaveData();

            dgv.CurrentCell = dgv.Rows[rowIdx].Cells["colItem"];
            dgv.BeginEdit(true);

            LogCheckAction(newNo, "항목 추가", 0, "", "", "(새 항목)");
            RefreshPhotoList();
        }

        private void BtnDeleteItem_Click(object sender, EventArgs e)
        {
            if (dgv.CurrentRow == null) return;
            int rowIdx = dgv.CurrentRow.Index;
            if (rowIdx < 0 || rowIdx >= dgv.Rows.Count) return;

            string itemName = dgv.Rows[rowIdx].Cells["colItem"].Value?.ToString() ?? "";
            var result = MessageBox.Show(
                $"항목 {rowIdx + 1} ({itemName})을(를) 삭제하시겠습니까?\n\n※ 해당 항목의 모든 월별 체크 데이터도 영향을 받습니다.",
                "항목 삭제 확인", MessageBoxButtons.YesNo, MessageBoxIcon.Warning);

            if (result != DialogResult.Yes) return;

            _loading = true;
            dgv.Rows.RemoveAt(rowIdx);
            for (int i = 0; i < dgv.Rows.Count; i++)
                dgv.Rows[i].Cells["colNo"].Value = (i + 1).ToString();
            _loading = false;

            SyncItemsFromGrid();
            SaveItems();
            SaveData();

            LogCheckAction(rowIdx + 1, itemName, 0, "", itemName, "삭제됨");
            RefreshPhotoList();
        }

        #endregion

        #region Grid 설정

        private void SetupGrid()
        {
            _loading = true;
            dgv.Columns.Clear();
            dgv.Rows.Clear();

            // 고정 컬럼
            AddColumn("colNo", "NO", 22, true);
            AddColumn("colItem", "점검 항목", 110, false);
            AddColumn("colStandard", "점검 기준", 80, false);
            AddColumn("colMethod", "방법", 38, false);
            AddColumn("colType", "구분", 35, false);

            // 범위별 일자 × 교대 컬럼
            GetRangeStartEnd(out int startDay, out int endDay);
            int daysInMonth = DateTime.DaysInMonth(_currentMonth.Year, _currentMonth.Month);

            for (int d = startDay; d <= endDay; d++)
            {
                for (int s = 0; s < 3; s++)
                {
                    var col = new DataGridViewTextBoxColumn();
                    col.Name = $"colDay{d}_{SHIFT_KEYS[s]}";
                    col.HeaderText = $"{d}\n{SHIFT_NAMES[s]}";
                    col.Width = 18;
                    col.MinimumWidth = 16;
                    col.ReadOnly = true;
                    col.SortMode = DataGridViewColumnSortMode.NotSortable;
                    col.DefaultCellStyle.Font = new Font("맑은 고딕", 7.5F, FontStyle.Bold);

                    // 교대별 배경색 구분
                    if (d > daysInMonth)
                    {
                        col.DefaultCellStyle.BackColor = Color.FromArgb(50, 50, 50);
                    }
                    else if (s == 0)
                        col.DefaultCellStyle.BackColor = Color.FromArgb(38, 38, 48); // 아침
                    else if (s == 1)
                        col.DefaultCellStyle.BackColor = Color.FromArgb(38, 44, 38); // 점심
                    else
                        col.DefaultCellStyle.BackColor = Color.FromArgb(44, 38, 38); // 저녁

                    dgv.Columns.Add(col);
                }
            }

            // 항목 행 추가
            for (int i = 0; i < _items.Count; i++)
            {
                int rowIdx = dgv.Rows.Add();
                var row = dgv.Rows[rowIdx];
                row.Cells["colNo"].Value = (i + 1).ToString();
                row.Cells["colItem"].Value = _items[i][0];
                row.Cells["colStandard"].Value = _items[i][1];
                row.Cells["colMethod"].Value = _items[i][2];
                row.Cells["colType"].Value = _items[i][3];
                row.Cells["colItem"].Style.Alignment = DataGridViewContentAlignment.MiddleLeft;
                row.Cells["colStandard"].Style.Alignment = DataGridViewContentAlignment.MiddleLeft;
            }

            // 고정 컬럼 (스크롤 시 왼쪽 고정)
            dgv.Columns["colType"].Frozen = true;

            // Auto-fill grid rows to remove empty space
            AdjustGridRowHeight();

            _loading = false;
        }

        /// <summary>
        /// Adjust row height to fill available grid space
        /// </summary>
        private void AdjustGridRowHeight()
        {
            if (dgv.Rows.Count == 0) return;
            int availableH = dgv.ClientSize.Height - dgv.ColumnHeadersHeight;
            if (availableH <= 0) return;
            int rowH = availableH / dgv.Rows.Count;
            if (rowH < 24) rowH = 24;
            foreach (DataGridViewRow row in dgv.Rows)
                row.Height = rowH;

            // Auto-fill date columns to use remaining width
            AdjustDateColumnWidth();
        }

        /// <summary>
        /// Distribute remaining horizontal space to date columns evenly
        /// </summary>
        private void AdjustDateColumnWidth()
        {
            // Calculate fixed columns total width
            int fixedW = 0;
            int dateColCount = 0;
            foreach (DataGridViewColumn col in dgv.Columns)
            {
                if (col.Name.StartsWith("colDay"))
                    dateColCount++;
                else
                    fixedW += col.Width;
            }
            if (dateColCount == 0) return;

            int availableW = dgv.ClientSize.Width - fixedW - SystemInformation.VerticalScrollBarWidth;
            if (availableW <= 0) return;
            int dateW = availableW / dateColCount;
            if (dateW < 16) dateW = 16;

            foreach (DataGridViewColumn col in dgv.Columns)
            {
                if (col.Name.StartsWith("colDay"))
                    col.Width = dateW;
            }
        }

        private void AddColumn(string name, string header, int width, bool readOnly)
        {
            var col = new DataGridViewTextBoxColumn();
            col.Name = name;
            col.HeaderText = header;
            col.Width = width;
            col.ReadOnly = readOnly;
            col.SortMode = DataGridViewColumnSortMode.NotSortable;
            dgv.Columns.Add(col);
        }

        #endregion

        #region 셀 편집 완료 → 항목 저장

        private void Dgv_CellEndEdit(object sender, DataGridViewCellEventArgs e)
        {
            if (_loading || e.RowIndex < 0) return;
            if (e.ColumnIndex >= 1 && e.ColumnIndex <= 4)
            {
                SyncItemsFromGrid();
                SaveItems();
                SaveData();
            }
        }

        #endregion

        #region 셀 클릭 → O/X 토글 + 로그

        private void Dgv_CellClick(object sender, DataGridViewCellEventArgs e)
        {
            if (_loading || e.RowIndex < 0 || e.ColumnIndex < FIXED_COL_COUNT) return;

            string colName = dgv.Columns[e.ColumnIndex].Name;
            if (!colName.StartsWith("colDay")) return;

            // colDay{d}_{M|A|E} 파싱
            string suffix = colName.Substring(6); // "d_M" or "dd_M"
            string[] parts = suffix.Split('_');
            if (parts.Length != 2) return;

            int day;
            if (!int.TryParse(parts[0], out day)) return;
            string shiftKey = parts[1];

            int daysInMonth = DateTime.DaysInMonth(_currentMonth.Year, _currentMonth.Month);
            if (day > daysInMonth) return;

            var cell = dgv.Rows[e.RowIndex].Cells[e.ColumnIndex];
            string current = cell.Value?.ToString()?.Trim() ?? "";

            // 순환: "" → O → X → ""
            string next;
            if (current == "") next = "O";
            else if (current == "O") next = "X";
            else next = "";

            cell.Value = next;
            ApplyCellColor(cell, next, colName);

            // 교대 이름 변환
            int shiftIdx = Array.IndexOf(SHIFT_KEYS, shiftKey);
            string shiftName = shiftIdx >= 0 ? SHIFT_FULL[shiftIdx] : shiftKey;

            string itemName = dgv.Rows[e.RowIndex].Cells["colItem"].Value?.ToString() ?? "";
            LogCheckAction(e.RowIndex + 1, itemName, day, shiftName, current, next);

            SaveData();
        }

        private void ApplyCellColor(DataGridViewCell cell, string value, string colName = "")
        {
            if (value == "O")
            {
                cell.Style.ForeColor = Color.LimeGreen;
                cell.Style.BackColor = Color.FromArgb(30, 60, 30);
            }
            else if (value == "X")
            {
                cell.Style.ForeColor = Color.Red;
                cell.Style.BackColor = Color.FromArgb(70, 25, 25);
            }
            else
            {
                cell.Style.ForeColor = ThemeManager.DarkTheme.TextPrimary;
                // 교대별 기본 배경색 복원
                if (colName.EndsWith("_M"))
                    cell.Style.BackColor = Color.FromArgb(38, 38, 48);
                else if (colName.EndsWith("_A"))
                    cell.Style.BackColor = Color.FromArgb(38, 44, 38);
                else if (colName.EndsWith("_E"))
                    cell.Style.BackColor = Color.FromArgb(44, 38, 38);
                else
                    cell.Style.BackColor = ThemeManager.DarkTheme.BackgroundMedium;
            }
        }

        #endregion

        #region 참조사진 (썸네일 목록)

        private int _selectedPhotoIndex = -1;  // 현재 선택된 사진 항목 인덱스

        private void Dgv_SelectionChanged(object sender, EventArgs e)
        {
            if (dgv.CurrentRow == null) return;
            int rowIdx = dgv.CurrentRow.Index;
            if (rowIdx < 0 || rowIdx >= dgv.Rows.Count) return;

            // 그리드 행 선택 시 해당 썸네일 하이라이트
            SelectPhotoThumb(rowIdx);
        }

        /// <summary>
        /// TableLayoutPanel based 7x2 grid thumbnail layout (14 slots)
        /// </summary>
        private void RefreshPhotoList()
        {
            panelPhotoScroll.SuspendLayout();
            panelPhotoScroll.Controls.Clear();

            const int COLS = 7;
            const int ROWS = 2;
            int maxSlots = COLS * ROWS;  // 14 slots
            int count = Math.Min(_items.Count, maxSlots);

            var tlp = new TableLayoutPanel();
            tlp.Dock = DockStyle.Fill;
            tlp.ColumnCount = COLS;
            tlp.RowCount = ROWS * 2;  // label row + image row per visual row
            tlp.Margin = Padding.Empty;
            tlp.Padding = Padding.Empty;
            tlp.CellBorderStyle = TableLayoutPanelCellBorderStyle.None;

            // Column sizes: equal percentage
            tlp.ColumnStyles.Clear();
            for (int c = 0; c < COLS; c++)
                tlp.ColumnStyles.Add(new ColumnStyle(SizeType.Percent, 100f / COLS));

            // Row sizes: label(14px) + image(fill) x 2
            tlp.RowStyles.Clear();
            tlp.RowStyles.Add(new RowStyle(SizeType.Absolute, 14));  // row0: label
            tlp.RowStyles.Add(new RowStyle(SizeType.Percent, 50));   // row1: image
            tlp.RowStyles.Add(new RowStyle(SizeType.Absolute, 14));  // row2: label
            tlp.RowStyles.Add(new RowStyle(SizeType.Percent, 50));   // row3: image

            for (int i = 0; i < maxSlots; i++)
            {
                int col = i % COLS;
                int visualRow = i / COLS;  // 0 or 1
                int lblRow = visualRow * 2;
                int imgRow = lblRow + 1;

                // Label
                var lbl = new Label();
                lbl.Text = i < count ? $"{i + 1}. {_items[i][0]}" : "";
                lbl.Dock = DockStyle.Fill;
                lbl.Font = new Font("맑은 고딕", 6.5F);
                lbl.ForeColor = Color.FromArgb(180, 180, 180);
                lbl.TextAlign = ContentAlignment.BottomLeft;
                lbl.Margin = new Padding(1, 0, 1, 0);
                lbl.Tag = i;
                lbl.Cursor = Cursors.Hand;
                lbl.Click += PhotoThumb_Click;
                tlp.Controls.Add(lbl, col, lblRow);

                // PictureBox
                var pb = new PictureBox();
                pb.Dock = DockStyle.Fill;
                pb.SizeMode = PictureBoxSizeMode.Zoom;
                pb.BorderStyle = BorderStyle.FixedSingle;
                pb.BackColor = Color.FromArgb(35, 35, 35);
                pb.Margin = new Padding(1, 1, 1, 1);
                pb.Tag = i;
                pb.Cursor = Cursors.Hand;
                pb.Click += PhotoThumb_Click;
                pb.DoubleClick += PhotoThumb_DoubleClick;
                if (i < count) LoadPhotoInto(pb, i);
                tlp.Controls.Add(pb, col, imgRow);
            }

            panelPhotoScroll.Controls.Add(tlp);
            panelPhotoScroll.ResumeLayout();

            if (count > 0)
                SelectPhotoThumb(0);
        }

        /// <summary>
        /// 지정 인덱스의 사진을 PictureBox에 로드
        /// </summary>
        private void LoadPhotoInto(PictureBox pb, int itemIndex)
        {
            string prefix = (itemIndex + 1).ToString("D2");
            string[] exts = { ".jpg", ".jpeg", ".png", ".bmp", ".gif" };
            foreach (var ext in exts)
            {
                string path = Path.Combine(_photoPath, prefix + ext);
                if (File.Exists(path))
                {
                    try
                    {
                        using (var fs = new FileStream(path, FileMode.Open, FileAccess.Read))
                        {
                            pb.Image?.Dispose();
                            pb.Image = Image.FromStream(fs);
                        }
                        return;
                    }
                    catch { }
                }
            }
            pb.Image?.Dispose();
            pb.Image = null;
        }

        /// <summary>
        /// 썸네일 클릭 → 해당 항목 선택
        /// </summary>
        private void PhotoThumb_Click(object sender, EventArgs e)
        {
            int idx = -1;
            if (sender is Control ctrl && ctrl.Tag is int tagIdx)
                idx = tagIdx;
            if (idx < 0 || idx >= dgv.Rows.Count) return;

            SelectPhotoThumb(idx);

            // 그리드에서 해당 행 선택
            dgv.ClearSelection();
            dgv.Rows[idx].Selected = true;
            dgv.CurrentCell = dgv.Rows[idx].Cells["colItem"];
        }

        /// <summary>
        /// Double-click thumbnail to open file dialog and set photo
        /// </summary>
        private void PhotoThumb_DoubleClick(object sender, EventArgs e)
        {
            int idx = -1;
            if (sender is Control ctrl && ctrl.Tag is int tagIdx)
                idx = tagIdx;
            if (idx < 0 || idx >= _items.Count) return;

            _selectedPhotoIndex = idx;
            BtnSetPhoto_Click(sender, e);
        }

        /// <summary>
        /// 선택된 썸네일 하이라이트 (테두리 색상 변경)
        /// </summary>
        private void SelectPhotoThumb(int index)
        {
            _selectedPhotoIndex = index;
            lblPhotoTitle.Text = index >= 0 && index < _items.Count
                ? $"{index + 1}. {_items[index][0]}"
                : "참조 사진";

            // Search inside TableLayoutPanel
            foreach (Control c in panelPhotoScroll.Controls)
            {
                var container = (c is TableLayoutPanel) ? c : panelPhotoScroll;
                foreach (Control child in container.Controls)
                {
                    if (child is PictureBox pb && pb.Tag is int pbIdx)
                    {
                        pb.BackColor = (pbIdx == index)
                            ? Color.FromArgb(0, 90, 158)  // selected
                            : Color.FromArgb(35, 35, 35);  // normal
                    }
                }
                if (c is TableLayoutPanel) break;
            }
        }

        /// <summary>
        /// 파일 다이알로그로 참조사진 선택/설정
        /// </summary>
        private void BtnSetPhoto_Click(object sender, EventArgs e)
        {
            int rowIdx = _selectedPhotoIndex;
            if (rowIdx < 0)
            {
                if (dgv.CurrentRow != null)
                    rowIdx = dgv.CurrentRow.Index;
            }
            if (rowIdx < 0 || rowIdx >= _items.Count)
            {
                MessageBox.Show("사진을 설정할 항목을 먼저 선택하세요.", "알림",
                    MessageBoxButtons.OK, MessageBoxIcon.Information);
                return;
            }

            string prefix = (rowIdx + 1).ToString("D2");

            using (var ofd = new OpenFileDialog())
            {
                ofd.Filter = "이미지 파일|*.jpg;*.jpeg;*.png;*.bmp;*.gif|모든 파일|*.*";
                ofd.Title = $"항목 {rowIdx + 1} ({_items[rowIdx][0]}) 참조 사진 선택";

                if (ofd.ShowDialog() != DialogResult.OK) return;

                try
                {
                    if (!Directory.Exists(_photoPath))
                        Directory.CreateDirectory(_photoPath);

                    // 기존 사진 삭제
                    string[] exts = { ".jpg", ".jpeg", ".png", ".bmp", ".gif" };
                    foreach (var ext in exts)
                    {
                        string oldPath = Path.Combine(_photoPath, prefix + ext);
                        if (File.Exists(oldPath))
                            File.Delete(oldPath);
                    }

                    // 새 사진 복사
                    string newExt = Path.GetExtension(ofd.FileName).ToLower();
                    string destPath = Path.Combine(_photoPath, prefix + newExt);
                    File.Copy(ofd.FileName, destPath, true);

                    // 해당 썸네일만 갱신 (search inside TLP)
                    Control searchContainer = panelPhotoScroll;
                    foreach (Control tc in panelPhotoScroll.Controls)
                    {
                        if (tc is TableLayoutPanel) { searchContainer = tc; break; }
                    }
                    foreach (Control c in searchContainer.Controls)
                    {
                        if (c is PictureBox pb && pb.Tag is int pbIdx && pbIdx == rowIdx)
                        {
                            LoadPhotoInto(pb, rowIdx);
                            break;
                        }
                    }

                    Logger.Log($"[일상점검] 항목 {rowIdx + 1} 사진 설정 완료");
                }
                catch (Exception ex)
                {
                    MessageBox.Show($"사진 설정 실패: {ex.Message}", "오류",
                        MessageBoxButtons.OK, MessageBoxIcon.Error);
                }
            }
        }

